var e=[{id:`L3_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_OTHER_NULL`,text:{KOREA:`여전히 엉망진창에 막무가내로군.`,JPN:`相変わらずメチャクチャで無鉄砲ね。`,ENG:`You're still a reckless, stubborn mess, I see.`,TWN:`糊塗又固執的性格一點都沒變。`},stage:{bg:`CA_YOOMINA_02`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_OTHER_NULL`,text:{KOREA:`그래도...... 확실히 한걸음씩 나아가고 있다는 건 인정해야겠지?`,JPN:`でも……確実に一歩ずつ進んでいるということは認めなくちゃ。`,ENG:`Still... I must admit you're making progress, one step at a time.`,TWN:`不過……我也得承認，妳有在一步一步地前進吧？`},stage:{bg:`CA_YOOMINA_02`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_OTHER_NULL`,text:{KOREA:`다시 만나서 즐거웠다. 유미나.`,JPN:`また会えて楽しかったよ、ヤナギ・ミナ。`,ENG:`It was a pleasure meeting you again. Yoo Mina.`,TWN:`很高興又見面了，劉米娜。`},stage:{bg:`CA_YOOMINA_02`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_OTHER_NULL`,text:{KOREA:`너라면 반드시`,JPN:`君なら必ず`,ENG:`I'm sure...`,TWN:`妳一定可以`},stage:{bg:`CA_YOOMINA_02`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_OTHER_NULL`,text:{KOREA:` 그녀를 구원`,JPN:`彼女を救い出す`,ENG:` you will save her...`,TWN:`救出她`},stage:{bg:`CA_YOOMINA_03`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_OTHER_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`CA_YOOMINA_02`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`미나 양?`,JPN:`ミナさん？`,ENG:`Mina?`,TWN:`米娜小姐？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`무슨 생각을 하고 계세요?`,JPN:`何を考え込んでいるのですか？`,ENG:`What are you thinking about?`,TWN:`妳在想什麼呢？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`아, 아무것도 아니야.`,JPN:`な、何でもない。`,ENG:`Oh, it's nothing.`,TWN:`沒、沒什麼。`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`그냥...... 무슨 기억이 떠오른 것 같아서.`,JPN:`ただ……何かの記憶がフラッシュバックして……`,ENG:`It’s just that... I thought I just remembered something.`,TWN:`只是……好像有什麼記憶一閃而過。`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:null,C:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`흐음...... 기억이라......`,JPN:`ふむ……記憶ですか……`,ENG:`Hmm... Remembered something, huh...`,TWN:`哼嗯…… 記憶……`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`그나저나, 그림자는 어떻게 됐어?`,JPN:`そんなことより、シャドウはどうなったの？`,ENG:`Anyway, what happened to the Shadow?`,TWN:`話說回來，暗影怎麼樣了？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`어라? 무슨 말씀이세요?`,JPN:`ん？　何をおっしゃってるんですか？`,ENG:`Hmm? What do you mean?`,TWN:`咦？妳在說什麼？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L22_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`방금 미나 양이 쓰러트렸잖아요.`,JPN:`先ほどミナさんが倒したじゃないですか。`,ENG:`You just defeated it.`,TWN:`米娜小姐剛才不是打敗它了嘛。`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L23_1`,type:`dialog`,speaker:`YOOMINA_FENRIR_NEXT_NULL`,text:{KOREA:`내, 내가?`,JPN:`わ、私が？`,ENG:`I-I did?`,TWN:`我、我嗎？`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L24_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`그럼요. 아주 멋진 실력이었어요.`,JPN:`そうです。お見事でしたよ。`,ENG:`Of course. It was most impressive.`,TWN:`是啊，妳的實力真的很不錯。`},stage:{bg:`CITY_STREET_NIGHT`,slots:{L:{char_id:`YOOMINA_FENRIR_NEXT_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JOOSHIYOON_FENRIR_NULL_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};